// Package gitlock provides recovery helpers for transient .git/index.lock
// contention. It is shared by the agent execute-loop and the bead
// auto-commit path so both benefit from identical recovery semantics.
package gitlock

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// StaleAge is the age after which a .git/index.lock with no identifiable live
// owner is considered stale and safe to remove.
//
// All DDx writers serialize through withMainGitLock (.ddx/.git-tracker.lock),
// so an unowned index.lock past this threshold represents either a crashed git
// process or an operator command that exited without cleanup.
var StaleAge = 30 * time.Second

// RecoveryAttempts bounds the total number of attempts (including the initial
// try) made by RunGitWithIndexLockRecovery.
const RecoveryAttempts = 3

// LiveOwnerWait is the wait between retries when a live process holds the lock.
// Short by design: stalling is not acceptable here.
var LiveOwnerWait = 500 * time.Millisecond

// IsIndexLockError reports whether the git output is the .git/index.lock-exists error.
func IsIndexLockError(output string) bool {
	lower := strings.ToLower(output)
	return strings.Contains(lower, "index.lock") &&
		(strings.Contains(lower, "file exists") || strings.Contains(lower, "another git process"))
}

// IndexLockPath returns the absolute path to .git/index.lock for projectRoot.
func IndexLockPath(projectRoot string) string {
	return filepath.Join(projectRoot, ".git", "index.lock")
}

// findGitRoot walks up from dir to find the directory that contains a .git
// entry. Returns dir unchanged if .git cannot be found (graceful fallback).
func findGitRoot(dir string) string {
	current := dir
	for {
		if _, err := os.Stat(filepath.Join(current, ".git")); err == nil {
			return current
		}
		parent := filepath.Dir(current)
		if parent == current {
			return dir
		}
		current = parent
	}
}

// IndexLockOwner attempts to identify the pid that currently holds lockPath
// open. Uses lsof if available on PATH. Returns (0, nil) if no owner can be
// determined. Failure to identify is not itself an error.
func IndexLockOwner(lockPath string) (int, error) {
	lsof, err := exec.LookPath("lsof")
	if err != nil {
		return 0, nil
	}
	out, err := exec.Command(lsof, "-t", "--", lockPath).Output()
	if err != nil {
		// lsof exits non-zero when no process has the file open.
		return 0, nil
	}
	s := strings.TrimSpace(string(out))
	if s == "" {
		return 0, nil
	}
	first := strings.SplitN(s, "\n", 2)[0]
	pid, perr := strconv.Atoi(strings.TrimSpace(first))
	if perr != nil {
		return 0, nil
	}
	return pid, nil
}

// IndexLockRecoveryResult describes the outcome of one recovery attempt
// against .git/index.lock.
type IndexLockRecoveryResult struct {
	// Removed is true if the lock file was deleted.
	Removed bool
	// OwnerPID is the pid identified as holding the lock, or 0 if unknown.
	OwnerPID int
	// OwnerAlive reports the liveness of OwnerPID at inspection time.
	// Meaningful only when OwnerPID != 0.
	OwnerAlive bool
	// Age is the lock-file age at inspection (zero if lock was missing).
	Age time.Duration
	// Reason is a human-readable summary suitable for log output.
	Reason string
}

// RecoverGitIndexLock inspects .git/index.lock under projectRoot. If the lock
// has no live owner — either lsof identifies a dead pid, or no pid holds it
// and the mtime is past StaleAge — the lock is removed. Otherwise the lock is
// left in place and the result describes the live owner.
//
// projectRoot may be a subdirectory of the git repo; RecoverGitIndexLock
// walks up to find the actual .git directory so callers that operate on
// subdirectories (e.g. .ddx/) still find the correct lock file.
func RecoverGitIndexLock(projectRoot string) (IndexLockRecoveryResult, error) {
	projectRoot = findGitRoot(projectRoot)
	lockPath := IndexLockPath(projectRoot)
	info, statErr := os.Lstat(lockPath)
	if statErr != nil {
		if os.IsNotExist(statErr) {
			return IndexLockRecoveryResult{Reason: "lock not present"}, nil
		}
		return IndexLockRecoveryResult{}, fmt.Errorf("stat %s: %w", lockPath, statErr)
	}
	age := time.Since(info.ModTime())
	pid, _ := IndexLockOwner(lockPath)

	if pid > 0 {
		alive := processAlive(pid)
		if !alive {
			if rmErr := os.Remove(lockPath); rmErr != nil && !os.IsNotExist(rmErr) {
				return IndexLockRecoveryResult{OwnerPID: pid, Age: age},
					fmt.Errorf("remove lock owned by dead pid %d: %w", pid, rmErr)
			}
			return IndexLockRecoveryResult{
				Removed: true, OwnerPID: pid, OwnerAlive: false, Age: age,
				Reason: fmt.Sprintf("removed: owner pid %d not alive (lock age %s)", pid, age.Round(time.Second)),
			}, nil
		}
		return IndexLockRecoveryResult{
			OwnerPID: pid, OwnerAlive: true, Age: age,
			Reason: fmt.Sprintf("live owner pid %d (lock age %s)", pid, age.Round(time.Second)),
		}, nil
	}

	if age >= StaleAge {
		if rmErr := os.Remove(lockPath); rmErr != nil && !os.IsNotExist(rmErr) {
			return IndexLockRecoveryResult{Age: age},
				fmt.Errorf("remove unowned stale lock (age %s): %w", age, rmErr)
		}
		return IndexLockRecoveryResult{
			Removed: true, Age: age,
			Reason: fmt.Sprintf("removed: no owner found, age %s >= stale threshold %s",
				age.Round(time.Second), StaleAge),
		}, nil
	}

	return IndexLockRecoveryResult{
		Age:    age,
		Reason: fmt.Sprintf("no owner found but lock is fresh (age %s < %s)", age.Round(time.Second), StaleAge),
	}, nil
}

// RunGitWithIndexLockRecovery runs `git args...` in dir and, on
// .git/index.lock contention, identifies the owner and either removes a stale
// lock or briefly waits for a live owner before retrying.
//
// Total attempts are bounded by RecoveryAttempts; the final error is decorated
// with the most recent recovery diagnostic. The helper deliberately does NOT
// loop for tens of seconds — stalling is not acceptable here.
func RunGitWithIndexLockRecovery(ctx context.Context, dir string, args ...string) ([]byte, error) {
	var lastOut []byte
	var lastErr error
	var lastDiag string
	for attempt := 0; attempt < RecoveryAttempts; attempt++ {
		out, err := internalgit.Command(ctx, dir, args...).CombinedOutput()
		if err == nil {
			return out, nil
		}
		if !IsIndexLockError(string(out)) {
			return out, err
		}
		lastOut = out
		lastErr = err
		result, recErr := RecoverGitIndexLock(dir)
		if recErr != nil {
			return out, fmt.Errorf("%s; index-lock recovery failed: %w", strings.TrimSpace(string(out)), recErr)
		}
		lastDiag = result.Reason
		if !result.Removed {
			time.Sleep(LiveOwnerWait)
		}
	}
	if lastDiag == "" {
		return lastOut, lastErr
	}
	return lastOut, fmt.Errorf("%s; index-lock owner: %s: %w",
		strings.TrimSpace(string(lastOut)), lastDiag, lastErr)
}

package workerstatus

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"time"
)

// LivenessRecord is the worker-side sidecar written under
// .ddx/workers/<worker-id>/status.json to mirror live progress of a
// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
//
// The bead tracker remains the durable claim marker; this sidecar carries
// the high-frequency liveness signal so operators can answer "is the worker
// alive and what is it doing?" without inflating tracker churn.
type LivenessRecord struct {
	WorkerID       string    `json:"worker_id"`
	ProjectRoot    string    `json:"project_root,omitempty"`
	CurrentBead    string    `json:"current_bead,omitempty"`
	AttemptID      string    `json:"attempt_id,omitempty"`
	Phase          string    `json:"phase,omitempty"`
	Route          string    `json:"route,omitempty"`
	Harness        string    `json:"harness,omitempty"`
	Model          string    `json:"model,omitempty"`
	Profile        string    `json:"profile,omitempty"`
	PID            int       `json:"pid,omitempty"`
	ChildPID       int       `json:"child_pid,omitempty"`
	StartedAt      time.Time `json:"started_at,omitempty"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// LivenessTTL is the freshness window for treating a worker sidecar as
// "active". Defaults to 3× the bead tracker heartbeat interval (which is
// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
var LivenessTTL = 90 * time.Second

// LivenessDir returns the worker sidecar directory for a project.
func LivenessDir(projectRoot string) string {
	return filepath.Join(projectRoot, ".ddx", "workers")
}

// LivenessPath returns the status.json path for a worker under projectRoot.
func LivenessPath(projectRoot, workerID string) string {
	return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
}

// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
// tmp-then-rename so concurrent readers never see a half-written file.
func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
	if projectRoot == "" || workerID == "" {
		return fmt.Errorf("workerstatus: project root and worker id required")
	}
	dir := filepath.Join(LivenessDir(projectRoot), workerID)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
	}
	data, err := json.MarshalIndent(rec, "", "  ")
	if err != nil {
		return fmt.Errorf("workerstatus: marshal liveness: %w", err)
	}
	data = append(data, '\n')
	final := filepath.Join(dir, "status.json")
	tmp, err := os.CreateTemp(dir, "status-*.tmp")
	if err != nil {
		return fmt.Errorf("workerstatus: create tmp: %w", err)
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: write tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: close tmp: %w", err)
	}
	if err := os.Rename(tmpName, final); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: rename: %w", err)
	}
	return nil
}

// ReadLiveness reads the sidecar for workerID under projectRoot.
func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
	var rec LivenessRecord
	data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
	if err != nil {
		return rec, err
	}
	if err := json.Unmarshal(data, &rec); err != nil {
		return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
	}
	return rec, nil
}

// ListLiveness reads every status.json sidecar under projectRoot's worker
// directory. Malformed sidecars are skipped silently — the sidecar is
// best-effort observability, not authoritative state.
func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
	dir := LivenessDir(projectRoot)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var out []LivenessRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := ReadLiveness(projectRoot, entry.Name())
		if err != nil {
			continue
		}
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		return out[i].LastActivityAt.After(out[j].LastActivityAt)
	})
	return out, nil
}

// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
func (r LivenessRecord) IsFresh(now time.Time) bool {
	if r.LastActivityAt.IsZero() {
		return false
	}
	return now.Sub(r.LastActivityAt) <= LivenessTTL
}

package workerstatus

import (
	"os"
	"path/filepath"
	"testing"
)

func TestInferBead_FromWorktreePath(t *testing.T) {
	cmdline := "ddx work --once"
	cwd := "/tmp/ddx-exec-wt/.execute-bead-wt-ddx-c3219628-20260513T231309-0e6f776b"

	beadID, worktree := InferBead(cmdline, cwd)
	if beadID != "ddx-c3219628" {
		t.Fatalf("bead id mismatch: got %q", beadID)
	}
	if worktree == "" {
		t.Fatalf("worktree should be populated from cwd, got empty")
	}
}

func TestInferBead_FromTryPositionalArg(t *testing.T) {
	cmdline := "ddx try ddx-abc12345 --no-review"
	cwd := "/home/user/project"

	beadID, worktree := InferBead(cmdline, cwd)
	if beadID != "ddx-abc12345" {
		t.Fatalf("bead id mismatch: got %q", beadID)
	}
	if worktree != "" {
		t.Fatalf("worktree should be empty when cwd is the project root, got %q", worktree)
	}
}

func TestInferBead_NoSignal(t *testing.T) {
	beadID, worktree := InferBead("ddx work --watch", "/home/user/project")
	if beadID != "" {
		t.Fatalf("bead id should be empty, got %q", beadID)
	}
	if worktree != "" {
		t.Fatalf("worktree should be empty, got %q", worktree)
	}
}

func TestFilterByProject_KeepsMatchesAndDropsOthers(t *testing.T) {
	dir := t.TempDir()
	other := t.TempDir()

	workers := []LiveWorker{
		{PID: 1, ProjectRoot: dir, Command: "ddx work"},
		{PID: 2, ProjectRoot: other, Command: "ddx work"},
		{PID: 3, ProjectRoot: dir, Command: "ddx try ddx-abc12345"},
	}

	got := FilterByProject(workers, dir)
	if len(got) != 2 {
		t.Fatalf("expected 2 workers for project A, got %d", len(got))
	}
	for _, w := range got {
		if w.ProjectRoot != dir {
			t.Errorf("filtered worker has wrong project root %q", w.ProjectRoot)
		}
	}
}

func TestFilterByProject_ResolvesSymlinkedProjectRoot(t *testing.T) {
	realDir := t.TempDir()
	link := filepath.Join(t.TempDir(), "link")
	if err := os.Symlink(realDir, link); err != nil {
		t.Skipf("symlink not supported in this environment: %v", err)
	}

	workers := []LiveWorker{
		{PID: 1, ProjectRoot: realDir, Command: "ddx work"},
	}
	got := FilterByProject(workers, link)
	if len(got) != 1 {
		t.Fatalf("expected symlink to match real path, got %d", len(got))
	}
}

func TestSamePath_EmptyInputs(t *testing.T) {
	if SamePath("", "/some/path") {
		t.Fatalf("empty paths must not match")
	}
	if SamePath("/some/path", "") {
		t.Fatalf("empty paths must not match")
	}
}

func TestLooksLikeDDxWorkerExcludesWorkHelperSubcommands(t *testing.T) {
	workers := []string{
		"ddx work",
		"ddx work --once",
		"ddx try ddx-12345678",
	}
	for _, cmdline := range workers {
		if !looksLikeDDxWorker(cmdline) {
			t.Fatalf("%q should be classified as a live worker", cmdline)
		}
	}

	helpers := []string{
		"ddx work analyze",
		"ddx work clear-cooldowns",
		"ddx work focus",
		"ddx work metrics",
		"ddx work plan",
		"ddx work status",
	}
	for _, cmdline := range helpers {
		if looksLikeDDxWorker(cmdline) {
			t.Fatalf("%q should not be classified as a live worker", cmdline)
		}
	}
}
